const items = $input.first().json.leads || [$input.first().json];

// Normalize leads from Apollo/LinkedIn export CSV
return items.map(lead => ({
  json: {
    email: lead.email || lead.Email || null,
    first_name: lead.first_name || lead.firstName || lead['First Name'] || '',
    last_name: lead.last_name || lead.lastName || lead['Last Name'] || '',
    company: lead.company || lead.company_name || lead['Company'] || '',
    title: lead.title || lead.job_title || lead['Title'] || '',
    linkedin_url: lead.linkedin_url || lead.linkedinUrl || lead['LinkedIn URL'] || lead['Person Linkedin Url'] || '',
    company_id: lead.company_id || 1,
    source: 'linkedin'
  }
}));

const lead = $input.first().json;

// No email — tag for LinkedIn outreach via GHL
console.log(`LinkedIn-only lead: ${lead.first_name} ${lead.last_name} at ${lead.company}`);
console.log(`LinkedIn: ${lead.linkedin_url}`);
console.log('Action: Tag for LinkedIn DM outreach in GHL');

return [{
  json: {
    ...lead,
    action: 'linkedin_outreach',
    note: 'No email found — route to LinkedIn DM outreach'
  }
}];
